Solve the 'Diamond Problem' output (Virtual Inheritance construction order):
```cpp
struct A { A() { cout << "A"; } };
struct B : virtual A { B() { cout << "B"; } };
struct C : virtual A { C() { cout << "C"; } };
struct D : B, C { D() { cout << "D"; } };
// main:
D obj;
```

What is the output? (Tricky: Default Arguments + Virtual Functions)
```cpp
class Base {
public:
    virtual void show(int x = 10) { cout << "Base:" << x; }
};
class Derived : public Base {
public:
    void show(int x = 20) override { cout << "Derived:" << x; }
};

int main() {
    Base* b = new Derived();
    b->show();
}
```

